```sql
CREATE OR REPLACE FUNCTION enforce_two_pending()
RETURNS trigger AS $$
BEGIN
    IF (SELECT COUNT(*) FROM order_events
        WHERE order_id = NEW.order_id
          AND status IN ('PENDING','IN_PROGRESS')) >= 2 THEN
        RAISE EXCEPTION 'Too many pending events for order %', NEW.order_id;
    END IF;
    RETURN NEW;
END;
$$ LANGUAGE plpgsql;

CREATE TRIGGER check_pending
BEFORE INSERT ON order_events
FOR EACH ROW EXECUTE FUNCTION enforce_two_pending();
```

