```js
/**
 * Perform a fetch with exponential back‑off.
 *
 * @param {string} url          – The endpoint to call.
 * @param {object} options     – Fetch options (method, headers, body, …).
 * @param {number} maxAttempts – How many total attempts (first try + retries).
 * @param {number} baseDelay   – Initial delay in ms (e.g., 500).
 * @param {number} factor       – Multiplicative factor for each retry (e.g., 2).
 * @returns {Promise<Response>}  – Resolves with the successful Response.
 */
async function fetchWithBackoff(url, options = {}, maxAttempts = 5, baseDelay = 500, factor = 2) {
  let attempt = 0;

  while (attempt < maxAttempts) {
    try {
      const response = await fetch(url, options);

      // If the response is OK (2xx) we’re done.
      if (response.ok) {
        return response;
      }

      // For non‑2xx status codes you may decide to retry or fail immediately.
      // Here we treat 5xx as retry‑able, others as fatal.
      if (!response.status.toString().startsWith('5')) {
        throw new Error(`Request failed with status ${response.status}`);
      }

      // If we reach here, it’s a 5xx error → fall through to retry logic.
      throw new Error(`Server error ${response.status}`);
    } catch (err) {
      attempt++;

      if (attempt >= maxAttempts) {
        // No more retries left – re‑throw the last error.
        throw err;
      }

      // Compute exponential delay with jitter to avoid thundering herd.
      const jitter = Math.random() * 100; // ±100 ms random jitter
      const delay = baseDelay * Math.pow(factor, attempt - 1) + jitter;

      console.warn(
        `Attempt ${attempt} failed: ${err.message}. Retrying in ${Math.round(
          delay
        )} ms...`
      );

      // Pause before the next attempt.
      await new Promise((resolve) => setTimeout(resolve, delay));
    }
  }
}

// Example usage:
(async () => {
  try {
    const response = await fetchWithBackoff('https://api.example.com/data', {
      method: 'GET',
      headers: { 'Content-Type': 'application/json' },
    });
    const data = await response.json();
    console.log('Got data:', data);
  } catch (e) {
    console.error('All retries failed:', e);
  }
})();
```

### How it works
1. **Loop & attempt counter** – The `while` loop runs until we either succeed or exhaust `maxAttempts`.
2. **Success path** – If `fetch` resolves and `response.ok` is true (status 200‑299), we return the response immediately.
3. **Retry‑able failures** – For network errors or HTTP 5xx responses we throw an error to trigger the `catch` block.
4. **Back‑off calculation** – `baseDelay * factor^(attempt‑1)` gives exponential growth; a small random jitter reduces the chance that many clients retry at the exact same moment.
5. **Delay** – `await new Promise(r => setTimeout(r, delay))` pauses the async function without blocking the event loop.
6. **Final failure** – After the last attempt the error is re‑thrown so the caller can handle it.

You can tweak `maxAttempts`, `baseDelay`, and `factor` to suit the reliability requirements of your API.

