```tsx
import { useState, useEffect, useCallback } from 'react';

// Helper: retry with timeout (same logic we covered earlier)
function retryWithTimeout<T>(
  fn: () => Promise<T>,
  retries: number,
  timeoutMs: number,
  delayMs = 0
): Promise<T> {
  return new Promise<T>((resolve, reject) => {
    let attempts = 0;
    let timedOut = false;
    const timer = setTimeout(() => {
      timedOut = true;
      reject(new Error('Operation timed out'));
    }, timeoutMs);

    const attempt = () => {
      if (timedOut) return;
      attempts++;
      fn()
        .then((result) => {
          clearTimeout(timer);
          resolve(result);
        })
        .catch((err) => {
          if (attempts > retries) {
            clearTimeout(timer);
            reject(err);
          } else {
            setTimeout(attempt, delayMs);
          }
        });
    };

    attempt();
  });
}

// The hook
export function useFetchWithRetry<T>(
  url: string,
  options?: RequestInit,
  retries = 3,
  timeoutMs = 5000,
  delayMs = 1000
) {
  const [data, setData] = useState<T | null>(null);
  const [error, setError] = useState<Error | null>(null);
  const [loading, setLoading] = useState<boolean>(true);

  const fetchData = useCallback(() => {
    // The actual fetch wrapped in a function for retryWithTimeout
    const fetchFn = () => fetch(url, options).then((res) => {
      if (!res.ok) {
        throw new Error(`HTTP ${res.status}`);
      }
      return res.json() as Promise<T>;
    });

    setLoading(true);
    setError(null);

    retryWithTimeout(fetchFn, retries, timeoutMs, delayMs)
      .then((result) => {
        setData(result);
        setLoading(false);
      })
      .catch((err) => {
        setError(err);
        setLoading(false);
      });
  }, [url, options, retries, timeoutMs, delayMs]);

  // Run once on mount (or when dependencies change)
  useEffect(() => {
    fetchData();
  }, [fetchData]);

  // Optional: expose a manual refetch function
  return { data, error, loading, refetch: fetchData };
}
```

