import { useState, useEffect, useCallback } from 'react';

type GraphQLResponse<T> = {
  data?: T;
  errors?: { message: string }[];
};

export function useGraphQL<T>(
  query: string,
  variables?: Record<string, any>,
  options?: RequestInit
) {
  const [data, setData] = useState<T | null>(null);
  const [loading, setLoading] = useState<boolean>(true);
  const [error, setError] = useState<string | null>(null);

  const fetchData = useCallback(async () => {
    setLoading(true);
    setError(null);
    try {
      const response = await fetch('/graphql', {
        method: 'POST',
        headers: {
          'Content-Type': 'application/json',
          ...(options?.headers || {}),
        },
        body: JSON.stringify({ query, variables }),
        ...options,
      });

      const json: GraphQLResponse<T> = await response.json();

      if (json.errors && json.errors.length) {
        setError(json.errors.map(e => e.message).join(', '));
      } else {
        setData(json.data as T);
      }
    } catch (e: any) {
      setError(e.message);
    } finally {
      setLoading(false);
    }
  }, [query, JSON.stringify(variables), JSON.stringify(options)]);

  useEffect(() => {
    fetchData();
  }, [fetchData]);

  return { data, loading, error, refetch: fetchData };
}
```

**How it works**

1. **Query & Variables** – Pass the GraphQL query string and an optional `variables` object when you call the hook.
2. **POST request** – The hook sends a POST to `/graphql` (adjust the URL if needed) with a JSON body containing `query` and `variables`.
3. **Response handling** – It checks for `errors` in the GraphQL response and surfaces them via the `error` state; otherwise it stores the `data`.
4. **Refetch** – The returned `refetch` function lets you manually re‑run the query (useful for pagination or after a mutation).

