import { useQuery, gql } from '@apollo/client';
import { useState, useCallback } from 'react';

// 1️⃣ Define the query with pagination arguments
const GET_ITEMS = gql`
  query GetItems($first: Int, $after: String, $last: Int, $before: String) {
    itemsConnection(
      first: $first
      after: $after
      last: $last
      before: $before
    ) {
      edges {
        node {
          id
          title
          // …other fields
        }
        cursor
      }
      pageInfo {
        hasNextPage
        hasPreviousPage
        startCursor
        endCursor
      }
    }
  }
`;

// 2️⃣ Hook that wraps the query and exposes pagination helpers
export function usePaginatedItems(initialPageSize = 10) {
  // Keep track of the current pagination variables
  const [variables, setVariables] = useState({
    first: initialPageSize,
    after: null,
    last: null,
    before: null,
  });

  const { data, loading, error, fetchMore, refetch } = useQuery(
    GET_ITEMS,
    {
      variables,
      notifyOnNetworkStatusChange: true, // lets us know when fetchMore is in flight
    }
  );

  // Helper to go to the next page
  const loadNext = useCallback(() => {
    if (!data?.itemsConnection.pageInfo.hasNextPage) return;

    setVariables({
      first: initialPageSize,
      after: data.itemsConnection.pageInfo.endCursor,
      last: null,
      before: null,
    });
  }, [data, initialPageSize]);

  // Helper to go to the previous page
  const loadPrev = useCallback(() => {
    if (!data?.itemsConnection.pageInfo.hasPreviousPage) return;

    setVariables({
      first: null,
      after: null,
      last: initialPageSize,
      before: data.itemsConnection.pageInfo.startCursor,
    });
  }, [data, initialPageSize]);

  // Optional: a manual refresh that resets pagination
  const reset = useCallback(() => {
    setVariables({
      first: initialPageSize,
      after: null,
      last: null,
      before: null,
    });
    refetch();
  }, [initialPageSize, refetch]);

  // Extract the list of items for convenience
  const items = data?.itemsConnection.edges.map(e => e.node) ?? [];

  return {
    items,
    loading,
    error,
    pageInfo: data?.itemsConnection.pageInfo,
    loadNext,
    loadPrev,
    reset,
  };
}
```

### How it works
1. **Query shape** – The GraphQL schema must expose a connection field (`itemsConnection`) that follows the Relay‑style pagination spec (edges, node, cursor, pageInfo).  
2. **Stateful variables** – We keep the pagination arguments (`first`, `after`, `last`, `before`) in local state so we can update them when the user navigates.  
3. **`loadNext` / `loadPrev`** – These callbacks compute the next set of variables based on the current `pageInfo` and trigger a re‑run of the query via the `variables` state change.  
4. **`notifyOnNetworkStatusChange`** – Allows the component to show a loading spinner only for the pagination request while keeping the existing list rendered.  
5. **`reset`** – Handy for a “Refresh” button that clears pagination and fetches the first page again.

### Using the hook in a component

```tsx
function ItemList() {
  const {
    items,
    loading,
    error,
    pageInfo,
    loadNext,
    loadPrev,
    reset,
  } = usePaginatedItems(5); // 5 items per page

  if (loading && items.length === 0) return <p>Loading…</p>;
  if (error) return <p>Error: {error.message}</p>;

  return (
    <div>
      <button onClick={reset}>Refresh</button>
      <ul>
        {items.map(item => (
          <li key={item.id}>{item.title}</li>
        ))}
      </ul>

      <div style={{ marginTop: 12 }}>
        <button onClick={loadPrev} disabled={!pageInfo?.hasPreviousPage}>
          ← Prev
        </button>
        <button onClick={loadNext} disabled={!pageInfo?.hasNextPage}>
          Next →
        </button>
      </div>
    </div>
  );
}
```

### Tips & Gotchas
- **Server side**: Ensure your resolver returns `edges` with a stable `cursor` (often a base‑64 encoded ID) and correct `pageInfo`.  
- **Cache handling**: Apollo’s default `InMemoryCache` merges paginated results automatically when you use the same query with different variables, but you may need to add a `keyArgs: false` policy for the connection field if you run into duplicate entries.  
- **Variable cleanup**: When switching between forward and backward pagination, always clear the opposite variables (`first` vs `last`) to avoid ambiguous requests.  

With this pattern you can plug the hook into any component that needs infinite scroll, “Load more” buttons, or classic “Prev/Next” pagination while keeping the GraphQL query logic tidy and reusable.

